<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Mini Desktop</title>
<style>
  body,html{margin:0;padding:0;height:100%;overflow:hidden;font-family:sans-serif;background:#2e3436;color:white;}
  #desktop{position:absolute;top:0;left:0;width:100%;height:100%;background:url('data:image/svg+xml;base64,PHN2ZyB3aWR0aD0iMTAwJSIgaGVpZ2h0PSIxMDAlIiB4bWxucz0iaHR0cDovL3d3dy53My5vcmcvMjAwMC9zdmciPjxyZWN0IHdpZHRoPSIxMDAlIiBoZWlnaHQ9IjEwMCUiIGZpbGw9IiM1NTU1NTUiIC8+PC9zdmc+') no-repeat center/cover;}
  #taskbar{position:absolute;bottom:0;left:0;width:100%;height:40px;background:#3d3d3d;border-top:1px solid #555;padding-left:5px;display:flex;align-items:center;}
  .launcher{margin-right:10px;padding:5px 10px;background:#4e4e4e;border-radius:4px;cursor:pointer;}
  .window{position:absolute;top:50px;left:50px;width:400px;height:300px;background:#2e3436;border:1px solid #555;border-radius:4px;box-shadow:0 0 10px rgba(0,0,0,.5);display:none;}
  .win-header{background:#3d3d3d;padding:5px;color:white;font-weight:bold;cursor:move;display:flex;justify-content:space-between;align-items:center;border-bottom:1px solid #555;}
  .win-close{cursor:pointer;background:#ff5c57;width:16px;height:16px;text-align:center;border-radius:50%;line-height:14px;color:white;font-weight:bold;}
  /* Files app */
  #files-window{width:500px;height:400px;top:60px;left:70px;}
  #files-path{padding:5px;background:#3d3d3d;border-bottom:1px solid #555;}
  #files-list{overflow:auto;padding:10px;}
  .fs-item{cursor:pointer;margin:2px 0;}
  /* Notepad app */
  #notepad-window{width:600px;height:500px;top:80px;left:90px;}
  #tabs{display:flex;background:#3d3d3d;border-bottom:1px solid #555;padding:5px;}
  .tab{padding:5px 10px;margin-right:2px;background:#4e4e4e;color:white;cursor:pointer;border-radius:4px 4px 0 0;}
  .tab.active{background:#2e3436;}
  #new-tab{margin-left:auto;padding:5px 10px;background:#4e4e4e;color:white;border:none;border-radius:4px;cursor:pointer;}
  #editor{width:100%;height:calc(100% - 40px);border:none;background:#1c1c1c;color:white;font-family:monospace;padding:10px;box-sizing:border-box;}
</style>
</head>
<body>
<div id="desktop"></div>

<div id="taskbar">
  <div class="launcher" id="open-files">Files</div>
  <div class="launcher" id="open-notepad">Notepad</div>
</div>

<!-- Files Window -->
<div class="window" id="files-window">
  <div class="win-header">
    <span>Files</span>
    <div class="win-close"></div>
  </div>
  <div id="files-path">/</div>
  <button id="files-up" style="margin:5px;">Up</button>
  <div id="files-list"></div>
</div>

<!-- Notepad Window -->
<div class="window" id="notepad-window">
  <div class="win-header">
    <span>Notepad</span>
    <div class="win-close"></div>
  </div>
  <div id="tabs"></div>
  <textarea id="editor"></textarea>
</div>

<script>
/* Utility */
function $(id){return document.getElementById(id);}
function create(name,cls){const e=document.createElement(name);if(cls)e.className=cls;return e;}
/* Window show/hide */
['files-window','notepad-window'].forEach(id=>{
  const win=$('#'+id);
  $('#open-'+id.split('-')[0]).onclick=e=>{win.style.display='block';};
  win.querySelector('.win-close').onclick=e=>{win.style.display='none';};
});

/* Files app */
const fsData={
  '/':{bin:{},etc:{},home:{user:{Documents:{},Downloads:{},Pictures:{}}},usr:{},var:{}}
};
let currentPath='/';
function renderFiles(){
  const list=$('#files-list');
  list.innerHTML='';
  const parts=currentPath.split('/').filter(Boolean);
  let dir=fsData['/'];
  for(const p of parts){dir=dir[p];}
  Object.keys(dir).forEach(name=>{
    const item=create('div','fs-item');item.textContent=name;
    if(typeof dir[name]==='object'){
      item.onclick=e=>{currentPath+=name+'/';renderFiles();};
    }
    list.appendChild(item);
  });
}
$('#files-up').onclick=e=>{
  if(currentPath!=='/') currentPath=currentPath.split('/').slice(0,-2).join('/')+'/';
  renderFiles();
};
renderFiles();

/* Notepad app */
const tabsEl=$('#tabs');
const editor=$('#editor');
let tabs=[];
function loadTabs(){
  const data=localStorage.getItem('notepad-tabs');
  if(data) tabs=JSON.parse(data);
}
function saveTabs(){localStorage.setItem('notepad-tabs',JSON.stringify(tabs));}
function renderTabs(){
  tabsEl.innerHTML='';
  tabs.forEach((t,i)=>{
    const tab=create('div','tab');tab.textContent=t.title||'Untitled';
    if(i===tabs.active) tab.classList.add('active');
    tab.onclick=e=>{switchTab(i);};
    tabsEl.appendChild(tab);
  });
  const newBtn=create('button','',null,'+');newBtn.id='new-tab';newBtn.onclick=addTab;
  tabsEl.appendChild(newBtn);
}
function switchTab(idx){
  if(tabs.active===idx)return;
  tabs[tabs.active].content=editor.value;
  tabs.active=idx;
  editor.value=tabs[idx].content||'';
  renderTabs();
}
function addTab(){
  const title='Untitled '+(tabs.length+1);
  tabs.push({title,content:''});
  switchTab(tabs.length-1);
  saveTabs();
}
$('#editor').oninput=e=>{if(tabs.active!==undefined)tabs[tabs.active].content=editor.value;saveTabs();};

loadTabs();
if(tabs.length===0)addTab();
else{
  tabs.active=0;
  editor.value=tabs[0].content||'';
}
renderTabs();

/* Simple drag */
document.querySelectorAll('.window').forEach(win=>{
  const header=win.querySelector('.win-header');
  let offsetX,offsetY;
  header.onmousedown=e=>{
    offsetX=e.clientX-win.offsetLeft;
    offsetY=e.clientY-win.offsetTop;
    document.onmousemove=move;
    document.onmouseup=up;
  };
  function move(e){win.style.left=(e.clientX-offsetX)+'px';win.style.top=(e.clientY-offsetY)+'px';}
  function up(){document.onmousemove=null;document.onmouseup=null;}
});
</script>
</body>
</html>
